SELECT id, sender_id, receiver_id, title, CASE WHEN LENGTH(content) > 80 THEN CONCAT(LEFT(content, 80), '...') ELSE content END AS content, msg_type, is_read, create_time FROM ntc_message WHERE receiver_id = #{receiverId}
AND is_read = #{isRead}
ORDER BY create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM ntc_message
WHERE receiver_id = #{receiverId}

    AND is_read = #{isRead}

SELECT COUNT(*) FROM ntc_message
WHERE receiver_id = #{receiverId}
  AND is_read = 0
